    req = request.get_json()
    
    index = req.get('index', 'data')
    script_code = req.get('script', '')
    agg_name = req.get('agg_name', 'custom_agg')
    field = req.get('field', '_source')
    
    query = {
        "size": 0,
        "aggs": {
            agg_name: {
                "scripted_metric": {
                    "init_script": "state.transactions = []",
                    "map_script": script_code,
                    "combine_script": "return state",
                    "reduce_script": "return states"
                }
            }
        }
    }
    
    result = es.search(index=index, body=query)
    
    return jsonify(result)


