@app.route('/execute', methods=['POST'])
def execute():
    req = request.get_json()
    
    index = req.get('index', 'data')
    script_code = req['script']
    operation = req.get('operation', 'search')
    params = req.get('params', {})
    
    if operation == 'search':
        query = {
            "query": {
                "match_all": {}
            },
            "script_fields": {
                "result": {
                    "script": {
                        "inline": script_code,
                        "lang": "painless",
                        "params": params
                    }
                }
            }
        }
        result = es.search(index=index, body=query)
    
    elif operation == 'aggregate':
        query = {
            "size": 0,
            "aggs": {
                "custom": {
                    "scripted_metric": {
                        "init_script": "state.data = []",
                        "map_script": script_code,
                        "combine_script": "return state.data",
                        "reduce_script": "return states",
                        "params": params
                    }
                }
            }
        }
        result = es.search(index=index, body=query)
    
    elif operation == 'update':
        doc_id = req.get('id')
        body = {
            "script": {
                "inline": script_code,
                "lang": "painless",
                "params": params
            }
        }
        result = es.update(index=index, id=doc_id, body=body)
    
    else:
        return jsonify({"error": "Invalid operation"}), 400
    
    return jsonify(result)


